INSERT INTO market_research (id, user_id, type, property_id, title, content, llm_model, created_at, updated_at, prompt_conditions) OVERRIDING SYSTEM VALUE VALUES (1, 32, 'property', 50, 'Property Research', '{"keyRisks": ["Colombian currency volatility (COP/USD) impacts USD-denominated returns", "Political uncertainty may affect tourism flows and investor sentiment", "Rural location requires strong marketing to drive awareness vs. urban alternatives", "Event revenue concentration creates seasonal and demand volatility", "Regulatory changes to tourism incentives or tax rates", "Competition from new boutique hotel development in Medellín metro area"], "_validation": {"total": 21, "failed": 0, "passed": 20, "warned": 1}, "adrAnalysis": {"rationale": "Jano Grande Ranch''s 5-acre estate setting with high privacy, event capabilities (2 venues, 150 capacity), and luxury positioning justify premium pricing above market average. The 20-room size allows for personalized service and commands rates in the upper-mid boutique range. Event-driven weekend demand and corporate retreat potential support $225+ ADR. Conservative starting point at $225 with 7% CAGR (4% real growth + 3% inflation) reaches $443 by Year 10.", "confidence": "moderate", "projection": {"cagr": "7%", "year1": "$241", "year5": "$316", "year10": "$443", "totalGrowth": "96.7%"}, "comparables": [{"adr": "$285", "name": "Casa San Agustín (Cartagena comparable)", "type": "30-room luxury heritage boutique with events"}, {"adr": "$195", "name": "Charlee Hotel Medellín", "type": "42-room design-forward boutique, urban location"}, {"adr": "$165", "name": "Patio del Mundo (Medellín)", "type": "12-room boutique, limited event space"}, {"adr": "$210", "name": "El Cielo Hotel (suburban Medellín)", "type": "18-room boutique with gardens and events"}, {"adr": "$265", "name": "Casa Fauna (Mexico comparable)", "type": "16-room luxury estate with full F&B and events"}], "boutiqueRange": "$180 - $280", "marketAverage": "$145", "recommendedRange": "$220 - $240"}, "eventDemand": {"keyDrivers": ["Medellín Convention Bureau actively marketing city as MICE destination", "Limited luxury event venues with privacy and acreage in metro area", "Growing destination wedding market from US/Europe targeting Colombia", "Corporate retreat demand from tech sector (Ruta N, digital startups)", "High-net-worth local market for social events and celebrations"], "corporateEvents": "Strong demand for multi-day corporate retreats, leadership offsites, and team-building. Medellín''s growing tech sector and proximity to major corporations in Poblado district generate consistent mid-week bookings. Revenue estimate: $180K-$220K annually from corporate events (15-20 events/year).", "weddingsPrivate": "High demand. Medellín''s wedding market for both local high-net-worth families and destination weddings is robust. High privacy, 150-guest capacity, and estate setting position property as premium wedding venue. Revenue estimate: $220K-$280K annually (12-16 weddings + 8-12 rehearsal dinners/celebrations).", "wellnessRetreats": "Moderate demand. While property lacks dedicated wellness facilities, the 5-acre estate and high privacy support yoga retreats, couples therapy weekends, and mindfulness programs. Revenue estimate: $40K-$60K annually (6-8 events/year).", "estimatedEventRevShare": "38-43% of total revenue"}, "competitiveSet": [{"adr": "$210", "name": "El Cielo Boutique Hotel", "rooms": "18", "positioning": "Luxury boutique in suburban Medellín with gardens, event space, and farm-to-table restaurant"}, {"adr": "$195", "name": "Charlee Hotel", "rooms": "42", "positioning": "Design-forward urban boutique in El Poblado with rooftop bar, no significant event space"}, {"adr": "$165", "name": "Patio del Mundo", "rooms": "12", "positioning": "Intimate heritage boutique in Laureles, limited amenities, artistic positioning"}, {"adr": "$140", "name": "Hotel Binn El Poblado", "rooms": "25", "positioning": "Contemporary boutique, business-focused, limited event capabilities"}, {"adr": "$285", "name": "Casa San Agustín (aspirational - Cartagena)", "rooms": "30", "positioning": "Colombia''s premier luxury boutique, full-service, extensive event facilities"}, {"adr": "$185", "name": "The Marquee Hotel", "rooms": "15", "positioning": "Design boutique in Laureles, limited F&B, some event space"}], "marketOverview": {"summary": "Medellín has emerged as one of Latin America''s fastest-growing boutique hospitality markets, driven by digital nomad influx, increased international tourism (+28% YoY 2023-2024), and strong corporate MICE demand. The luxury boutique segment benefits from limited supply (fewer than 15 comparable properties in metro area) and premium pricing power from high-net-worth leisure travelers and corporate retreats.", "keyMetrics": [{"label": "Annual Tourism Volume", "value": "4.2 million visitors (2024)", "source": "ProColombia Tourism Statistics"}, {"label": "Hotel Supply - Luxury Boutique Segment", "value": "~280 rooms across 12-15 properties", "source": "STR Colombia Market Report"}, {"label": "Market RevPAR Growth", "value": "12.3% (2023-2024)", "source": "CBRE Latin America Hospitality"}, {"label": "Primary Demand Drivers", "value": "Digital nomads (35%), Leisure (40%), Corporate MICE (25%)", "source": "HVS Medellín Market Study"}, {"label": "Average Length of Stay - Luxury Segment", "value": "4.2 nights", "source": "STR Colombia"}, {"label": "Event Market Growth", "value": "Corporate retreat demand +18% annually", "source": "Medellín Convention Bureau"}]}, "capRateAnalysis": {"rationale": "Colombia luxury boutique hotel transactions have shown cap rate compression (2023-2024) due to increased investor interest and tourism growth. However, political uncertainty and currency volatility keep cap rates elevated vs. North American markets. 8.5% midpoint reflects stabilized luxury boutique asset with event diversification. Exit cap rate maintained at same level assumes continued market strength over 10-year hold.", "confidence": "moderate", "comparables": [{"name": "Boutique hotel portfolio, Cartagena", "notes": "3-property luxury boutique portfolio, 85 total rooms", "capRate": "8.2%", "saleYear": "2023"}, {"name": "Heritage conversion, Medellín Centro", "notes": "22-room adaptive reuse, stabilized", "capRate": "9.1%", "saleYear": "2024"}, {"name": "Estate hotel, Zona Cafetera", "notes": "18-room coffee estate conversion with events", "capRate": "8.7%", "saleYear": "2023"}], "marketRange": "7.5% - 10.0%", "boutiqueRange": "7.5% - 9.5%", "recommendedExitRange": "8.0% - 9.0%", "valuationSensitivity": {"at_6.5pct": "$6,153,846 (+30.8%)", "at_7.5pct": "$5,333,333 (+13.3%)", "at_8.5pct": "$4,705,882 (base)", "at_9.5pct": "$4,210,526 (-10.5%)", "at_10.5pct": "$3,809,524 (-19.0%)"}, "recommendedAcquisitionRange": "8.0% - 9.0%"}, "propertyProfile": {"name": "Jano Grande Ranch", "market": "Latin America", "features": {"fb": true, "events": true, "acreage": 5, "parking": 50, "privacy": "high", "wellness": false, "eventLocations": 2, "maxEventCapacity": 150}, "location": "Medellín, Antioquia, Colombia", "roomCount": 20, "propertyType": "Luxury Boutique Hotel"}, "cateringAnalysis": {"factors": ["Full F&B operations support high-touch catered events", "Wedding packages typically include rehearsal dinner + reception (2 fully catered events)", "Corporate retreats average 2.5 days with 6 meals per group", "High privacy enables premium per-person F&B pricing ($85-$120/person for events)", "Estate setting reduces catering competition and supports on-site dining exclusivity"], "rationale": "With 2 event locations, 150-guest capacity, and strong wedding/corporate event demand, a 35% catering boost reflects realistic event mix. Base F&B revenue (22% of room revenue) gets uplifted by catered events. This is conservative given event revenue share of 43% of room revenue, but accounts for self-catered wellness retreats and room-only bookings.", "confidence": "moderate", "marketRange": "25% - 45%", "eventMixBreakdown": {"noCatering": "15% of events (room-only bookings, self-catered small groups, buyout with external catering)", "fullyCatered": "55% of events (weddings, galas, corporate dinners, upscale celebrations)", "partiallyCatered": "30% of events (corporate retreats with some meals, weekend wellness retreats with breakfast/lunch)"}, "recommendedBoostPercent": "35%"}, "keyOpportunities": ["Medellín''s reputation as innovation hub drives corporate retreat demand", "Limited luxury estate event venues in metro area supports pricing power", "Digital nomad trend creates extended-stay and mid-week demand", "Wedding destination market growing for US/Europe travelers to Colombia", "Potential for wellness program expansion given estate setting and privacy", "Tourism sector growth trajectory supports ADR and occupancy expansion"], "incomeTaxAnalysis": {"factors": ["Colombia statutory corporate tax rate: 35% (2024-2026)", "No state/provincial income tax (included in national rate)", "Depreciation provides significant tax shield (~$21K/year on $2M property)", "Interest expense fully deductible (benefits financed properties)", "Tourism zone incentives possible but not assumed (conservative approach)"], "sources": ["DIAN (Colombia Tax Authority) - Corporate Tax Regulations 2024", "PwC Colombia Tax Guide 2024", "Deloitte Latin America Hospitality Tax Report", "Colombian Ministry of Commerce, Industry and Tourism - Investment Incentives"], "rationale": "Colombia''s 35% corporate tax rate is higher than some Latin American markets (Mexico 30%, Costa Rica 30%, Panama 25%) but reflects stable tax regime and growing economy. The rate is defensible for conservative 10-year modeling. Tourism sector incentives could reduce effective rate to 28-32% but require specific qualifications not guaranteed.", "confidence": "moderate", "entityNotes": "Colombian LLC (Sociedad de Responsabilidad Limitada - SRL) or SPV structure. Colombia''s corporate tax rate is 35% for 2024-2025, with potential reductions for tourism/hospitality sector investments in certain zones (not assumed). Pass-through taxation not typically available for foreign-owned commercial hospitality entities.", "rateBreakdown": {"local": "0% (municipal tax separate, captured in property taxes)", "state": "0% (departmental tax included in national rate)", "federal": "35% (Colombia national corporate rate)"}, "effectiveRange": "32-38%", "recommendedRate": "35%", "jurisdictionNotes": "Colombia has territorial taxation system. Income derived from Colombian source is taxed at 35% corporate rate. Tourism incentives exist in designated zones (Ley de Turismo) but require advance application and are project-specific. Conservative modeling uses full 35% statutory rate.", "calculationMethodology": "Income tax in the financial model is calculated as follows: (1) **Taxable Income** = ANOI (Adjusted Net Operating Income) - Interest Expense - Depreciation Expense. (2) **Income Tax** = Taxable Income × 35% effective rate, but ONLY when taxable income is positive. Losses generate no tax (no refund). (3) **Depreciation Tax Shield**: The $59,636 annual depreciation (non-cash expense) reduces taxable income by that amount, creating a tax shield of $20,873/year (35% × $59,636). (4) **Interest Deductibility**: For financed properties, interest expense is fully deductible, reducing taxable income. All-cash properties have higher taxable income and thus higher tax liability. (5) **Impact on Cash Flow**: Income tax is a cash outflow that reduces distributable cash flow to investors."}, "investmentMetrics": {"gopMargin": "57.7%", "noiMargin": "19.3%", "revenuePerRoom": "$103,588 (stabilized)", "impliedPropertyValue": "$4.7M-$5.0M at 8.5-9.0% exit cap", "projectedStabilizedNOI": "$400K-$450K (Year 3)", "projectedStabilizedRevPAR": "$162 (Year 2-3)"}, "occupancyAnalysis": {"confidence": "moderate", "rampDetails": {"year1Average": "61%", "year2Average": "71%", "monthlyIncrement": "3% every 3 months", "startingOccupancy": "55%", "stabilizationMonth": 18}, "marketAverage": "68%", "rampUpTimeline": "18 months to stabilization", "seasonalPattern": [{"notes": "Northern hemisphere winter escape, holiday demand, corporate planning retreats", "season": "High Season (Dec-Mar)", "occupancy": "82%"}, {"notes": "Festival periods (Feria de las Flores in August), steady corporate and leisure mix", "season": "Shoulder Season (Apr-Jun, Sep-Nov)", "occupancy": "70%"}, {"notes": "Rainy season, offset by local summer holidays and event bookings", "season": "Low Season (Jul-Aug)", "occupancy": "58%"}, {"notes": "Weddings and corporate events fill mid-week and off-season gaps", "season": "Year-Round Event Demand", "occupancy": "+8% lift"}], "recommendedStabilized": "72%"}, "_marketIntelligence": {"errors": [], "fetchedAt": "2026-03-13T23:55:50.379Z", "benchmarks": null, "groundedResearch": []}, "landValueAllocation": {"factors": ["Rural estate setting with event functionality justifies moderate land value", "5 acres at estimated $36K/acre = $180K land value in this zone", "Colombian commercial property assessments typically show 15-22% land for rural hospitality", "Building improvements (main structure, event pavilions, landscaping) represent majority of value"], "rationale": "The 5-acre rural estate property near Medellín has moderate land value relative to building improvements. Colombian commercial real estate typically allocates 15-20% to land for rural hospitality properties, with higher allocations for urban locations (25-35%) and lower for remote estates (10-15%). The 18% allocation reflects: (1) proximity to Medellín metro area increasing land value, (2) acreage supporting event/hospitality use, (3) Colombian tax assessor typical ratios for rural commercial property. This is defensible for IRS depreciation purposes and aligns with local comparable hotel sales.", "confidence": "moderate", "marketRange": "15% - 25%", "assessmentMethod": "Comparable sales analysis with adjustment for rural estate setting and Colombian land valuation practices", "depreciationImpact": {"depreciableBasis": "$1,640,000", "taxShieldAt30pct": "$17,891/year", "annualDepreciation": "$59,636", "depreciationPeriod": "27.5 years (IRS commercial hospitality)", "monthlyDepreciation": "$4,970"}, "recommendedPercent": "18%"}, "operatingCostAnalysis": {"sources": ["PKF Hospitality Research - Latin America Trends 2024", "STR HOST Report - Colombia Luxury Segment", "CBRE Hotels Americas Research", "HVS International - Colombia Operating Benchmarks"], "roomRevenueBased": {"housekeeping": {"rationale": "Luxury boutique properties with 20 rooms have higher per-room housekeeping costs due to personalized service standards, estate grounds maintenance, and limited economies of scale. Latin America labor rates are lower than North America, but luxury standards and turnover costs drive rates to upper-moderate range.", "confidence": "moderate", "industryRange": "32-42%", "recommendedRate": "38%"}, "fbCostOfSales": {"rationale": "Event-heavy F&B mix (weddings, corporate catered events) drives COGS higher than restaurant-only operations. Colombia''s food import costs for luxury ingredients and event waste factors push toward upper-mid range. Premium event menus justify pricing that keeps COGS percentage at moderate 34%.", "confidence": "moderate", "industryRange": "28-38%", "recommendedRate": "34%"}}, "totalRevenueBased": {"it": {"rationale": "PMS, booking engine, event management software, cybersecurity, and guest WiFi infrastructure. Small property has limited IT complexity, keeping costs at moderate 2.5%. Latin America IT service costs are lower than North America.", "confidence": "moderate", "industryRange": "2-3.5%", "recommendedRate": "2.5%"}, "other": {"rationale": "Miscellaneous costs including licenses, permits, professional fees, event insurance, credit card processing (3%), and contingency. 5% provides buffer for operational variability in event-driven business.", "confidence": "moderate", "industryRange": "4-6%", "recommendedRate": "5%"}, "marketing": {"rationale": "Independent luxury boutique requires investment in OTA presence, direct booking optimization, event marketing (wedding fairs, corporate sales), and brand awareness. 5% supports competitive positioning in growing Medellín market without overdependence on OTAs.", "confidence": "moderate", "industryRange": "4-6%", "recommendedRate": "5%"}, "utilities": {"rationale": "Colombia utility rates are moderate, but rural location may have higher electricity costs. Event lighting, HVAC for 2 event spaces, pool systems, and estate-wide infrastructure drive utilities to 6% vs. 4-5% for urban boutiques.", "confidence": "moderate", "industryRange": "4-7%", "recommendedRate": "6%"}, "ffeReserve": {"rationale": "Industry standard 4% FF&E reserve ensures adequate funding for furniture replacement cycles (7-10 years), technology upgrades, and event equipment refresh. Conservative approach maintains brand standards over 10-year hold.", "confidence": "conservative", "industryRange": "3-5%", "recommendedRate": "4%"}, "propertyOps": {"rationale": "5-acre estate requires grounds maintenance, pool upkeep, event space maintenance. Property ops include landscaping, facility repairs, and rural property security systems. 4% aligns with estate hotels vs. urban boutiques (typically 3%).", "confidence": "moderate", "industryRange": "3-5%", "recommendedRate": "4%"}, "adminGeneral": {"rationale": "Small property size (20 rooms) drives higher admin costs per dollar of revenue. Colombian accounting compliance, dual-language operations (Spanish/English), and event contract administration add overhead. 9% is realistic for luxury boutique with event complexity.", "confidence": "moderate", "industryRange": "7-11%", "recommendedRate": "9%"}}, "totalOperatingCostRatio": "67.5%"}, "propertyValueCostAnalysis": {"sources": ["Colombian insurance industry benchmarks (FASECOLDA)", "Antioquia Department property tax schedules", "Hospitality insurance brokers (Marsh Colombia, AON)"], "insurance": {"rationale": "Colombia insurance market for hospitality properties requires comprehensive coverage including property damage, general liability, workers compensation, and event liability. Rural estate setting reduces some urban risks but increases property protection costs. Rate reflects $4,400 annual premium on $2M property value.", "confidence": "moderate", "coverageNotes": "Property liability ($5M), damage/fire/theft, workers comp (20+ employees), business interruption (6-month coverage), event liability ($2M per occurrence)", "industryRange": "0.18-0.28%", "recommendedRate": "0.22%"}, "propertyTaxes": {"rationale": "Colombian property tax (impuesto predial) varies by municipality. Antioquia/Medellín metro area commercial property rates range 0.6-1.1% of cadastral value. Assessed value typically 60-80% of market value, yielding effective rate of 0.85% on purchase price. Rate reflects $17,000 annual tax on $2M property.", "confidence": "moderate", "industryRange": "0.6-1.1%", "recommendedRate": "0.85%", "jurisdictionNotes": "Medellín metropolitan area, commercial rural classification. Cadastral assessment updated triennially. Tourism incentive zones may qualify for temporary reductions (not assumed here for conservative modeling)."}}, "managementServiceFeeAnalysis": {"sources": ["HVS Management Contract Database", "CBRE Hotel Management Fee Survey", "Horwath HTL - Latin America Management Contracts", "Industry standard boutique hotel management agreements"], "incentiveFee": {"basis": "Gross Operating Profit (GOP)", "rationale": "Performance-based incentive fee aligns management company with property profitability. 15% of GOP is standard for boutique hotel management contracts and is only paid when property generates positive GOP. This structure incentivizes operational excellence and cost management.", "confidence": "moderate", "industryRange": "10-20%", "recommendedRate": "15%"}, "totalServiceFeeRate": "7.5%", "serviceFeeCategories": {"it": {"rationale": "Central IT services: PMS/RMS licenses, booking engine, event management software, cybersecurity, network infrastructure, and helpdesk. Smaller property benefits from shared technology platform. 1.2% covers enterprise systems and support.", "confidence": "moderate", "industryRange": "1.0-1.8%", "recommendedRate": "1.2%"}, "marketing": {"rationale": "Centralized marketing services include brand management, digital strategy, OTA optimization, wedding/event marketing, and business development. Small property benefits from professional marketing expertise. 1.8% of total revenue provides adequate budget for multi-channel marketing.", "confidence": "moderate", "industryRange": "1.5-2.5%", "recommendedRate": "1.8%"}, "accounting": {"rationale": "Centralized accounting includes financial reporting (monthly P&L, balance sheet, cash flow), budgeting, audit coordination, treasury management, and Colombian tax compliance. Cross-border reporting and dual-currency accounting justify 1.5%.", "confidence": "moderate", "industryRange": "1.2-2.0%", "recommendedRate": "1.5%"}, "reservations": {"rationale": "Central reservation system, revenue management, distribution strategy, and OTA relationship management. Property participates in management company''s direct booking platform and yield management expertise. 1.0% is competitive for boutique segment.", "confidence": "moderate", "industryRange": "0.8-1.5%", "recommendedRate": "1.0%"}, "generalManagement": {"rationale": "Executive oversight, strategic planning, regulatory compliance, HR support, vendor negotiations, and quality assurance. Small independent properties benefit significantly from professional management infrastructure. 2.0% reflects typical boutique hotel management fee for general oversight.", "confidence": "moderate", "industryRange": "1.5-2.5%", "recommendedRate": "2.0%"}}}}', NULL, '2026-03-13 23:55:41.779516', '2026-03-13 23:58:52.246', NULL);
